from docx import Document
from docx.shared import Pt, RGBColor
from docx.enum.text import WD_ALIGN_PARAGRAPH
from docx.enum.style import WD_STYLE_TYPE
from docx.oxml.ns import qn

# ===================== 1. 全局样式设置 =====================
def set_styles(doc):
    # 中文字体设置函数
    def set_chinese(run):
        run.font.name = '宋体'
        run._element.rPr.rFonts.set(qn('w:eastAsia'), '宋体')

    # 主标题
    if 'Main Title' not in [s.name for s in doc.styles]:
        t1 = doc.styles.add_style('Main Title', WD_STYLE_TYPE.PARAGRAPH)
        t1.font.name = '黑体'
        set_chinese(t1.font)
        t1.font.size = Pt(24)
        t1.font.bold = True
        t1.paragraph_format.alignment = WD_ALIGN_PARAGRAPH.CENTER
        t1.paragraph_format.space_before = Pt(30)
        t1.paragraph_format.space_after = Pt(20)

    # 一级标题（大/小阿卡纳总分类）
    if 'L1 Heading' not in [s.name for s in doc.styles]:
        l1 = doc.styles.add_style('L1 Heading', WD_STYLE_TYPE.PARAGRAPH)
        l1.font.name = '黑体'
        set_chinese(l1.font)
        l1.font.size = Pt(20)
        l1.font.bold = True
        l1.paragraph_format.space_before = Pt(25)
        l1.paragraph_format.space_after = Pt(15)

    # 二级标题（大阿卡纳阶段/小阿卡纳四组）
    if 'L2 Heading' not in [s.name for s in doc.styles]:
        l2 = doc.styles.add_style('L2 Heading', WD_STYLE_TYPE.PARAGRAPH)
        l2.font.name = '黑体'
        set_chinese(l2.font)
        l2.font.size = Pt(16)
        l2.font.bold = True
        l2.paragraph_format.space_before = Pt(20)
        l2.paragraph_format.space_after = Pt(10)

    # 三级标题（单张牌）
    if 'L3 Heading' not in [s.name for s in doc.styles]:
        l3 = doc.styles.add_style('L3 Heading', WD_STYLE_TYPE.PARAGRAPH)
        l3.font.name = '黑体'
        set_chinese(l3.font)
        l3.font.size = Pt(14)
        l3.font.bold = True
        l3.paragraph_format.space_before = Pt(15)
        l3.paragraph_format.space_after = Pt(8)

    # 正文
    if 'Body' not in [s.name for s in doc.styles]:
        body = doc.styles.add_style('Body', WD_STYLE_TYPE.PARAGRAPH)
        body.font.name = '宋体'
        set_chinese(body.font)
        body.font.size = Pt(12)
        body.paragraph_format.first_line_indent = Pt(24)
        body.paragraph_format.line_spacing = 1.5
        body.paragraph_format.space_after = Pt(6)

    # 重点强调
    if 'Emphasis' not in [s.name for s in doc.styles]:
        emph = doc.styles.add_style('Emphasis', WD_STYLE_TYPE.PARAGRAPH)
        emph.font.name = '宋体'
        set_chinese(emph.font)
        emph.font.size = Pt(12)
        emph.font.bold = True
        emph.paragraph_format.line_spacing = 1.5
        emph.paragraph_format.space_after = Pt(6)

