# ===================== 3. 文档生成逻辑 =====================
def generate_doc():
    doc = Document()
    set_styles(doc)

    # 标题
    doc.add_paragraph('78张韦特塔罗牌完整深度解读', style='Main Title')
    doc.add_paragraph('大阿卡纳22张+小阿卡纳56张 全牌面·原型·心理·正逆位详解', style='Sub Title')

    # 前言
    doc.add_paragraph('前言', style='L2 Heading')
    intro = doc.add_paragraph('韦特塔罗牌由22张大阿卡纳与56张小阿卡纳组成，共78张牌，构成了一套完整的生命成长体系。大阿卡纳描绘了「愚人之旅」的灵魂成长轨迹，从0号愚人懵懂出发，历经世俗历练、心智成熟、灵性觉醒，最终在21号世界牌抵达身心灵的终极合一，掌管人生的核心课题与灵魂真相；小阿卡纳以火、水、风、土四元素为基础，分为权杖、圣杯、宝剑、星币四组，每组14张牌，掌管日常生活的具体课题，涵盖行动、情感、思维、物质四大维度，是大阿卡纳核心课题在现实生活中的落地与体现。', style='Body')
    intro = doc.add_paragraph('本解读以韦特塔罗牌经典牌面为基础，为每一张牌提供**牌面细节解读**、**核心原型定位**、**心理层面意义**、**正位核心解读**、**逆位核心解读**（含消极走向与积极走向），既保留塔罗牌的经典象征意义，又结合现代心理视角，让解读更贴合当代人的生命体验。塔罗牌的核心并非预测未来，而是照见内心，通过牌面的象征唤醒自我认知，引导我们做出符合内心的选择，最终成为完整、真实、喜悦的自己。', style='Body')

    data = get_tarot_data()

    # -------------------- 大阿卡纳 --------------------
    doc.add_paragraph('第一部分：22张大阿卡纳——愚人之旅的灵魂成长轨迹', style='L1 Heading')
    for card in data["major"]:
        doc.add_paragraph(f'{card["num"]} {card["name"]}', style='L3 Heading')
        doc.add_paragraph('【牌面解读】', style='Emphasis')
        doc.add_paragraph(card["image"], style='Body')
        doc.add_paragraph('【核心原型】', style='Emphasis')
        doc.add_paragraph(card["core"], style='Body')
        doc.add_paragraph('【心理层面】', style='Emphasis')
        doc.add_paragraph(card["psychology"], style='Body')
        doc.add_paragraph('【正位核心】', style='Emphasis')
        doc.add_paragraph(card["upright"], style='Body')
        doc.add_paragraph('【逆位核心】', style='Emphasis')
        doc.add_paragraph('消极走向：' + card["reverse_neg"], style='Body')
        doc.add_paragraph('积极走向：' + card["reverse_pos"], style='Body')

    # -------------------- 小阿卡纳 --------------------
    doc.add_paragraph('第二部分：56张小阿卡纳——日常生命课题的完整指引', style='L1 Heading')
    for suit_name, cards in data["minor"].items():
        doc.add_paragraph(suit_name, style='L2 Heading')
        for card in cards:
            doc.add_paragraph(f'{card["num"]} {card["name"]}', style='L3 Heading')
            if "image" in card:
                doc.add_paragraph('【牌面解读】', style='Emphasis')
                doc.add_paragraph(card["image"], style='Body')
            if "core" in card:
                doc.add_paragraph('【核心能量】', style='Emphasis')
                doc.add_paragraph(card["core"], style='Body')
            doc.add_paragraph('【正位核心】', style='Emphasis')
            doc.add_paragraph(card["upright"], style='Body')
            doc.add_paragraph('【逆位核心】', style='Emphasis')
            doc.add_paragraph('消极走向：' + card["reverse_neg"], style='Body')
            doc.add_paragraph('积极走向：' + card["reverse_pos"], style='Body')

    # 保存文档
    doc.save('78张韦特塔罗牌完整深度解读.docx')
    print('✅ 文档生成成功！文件名：78张韦特塔罗牌完整深度解读.docx')

